    /**
	 * 删除iframe
	 * @param {object} args
	 * @param {SCarg} args.id
	 */
	deleteiframe(args) {
		if (this.iframeParent() === null) {
			return;
		}
		const iframes = document.getElementById(`AerIframe${args.id}`);
		if (iframes !== null) {
			this.iframeParent().removeChild(iframes);
		}
	}

